@dataclass
class Dependency:
    """Represents a single Python dependency."""
    name: str
    version: str
    hashes: List[str] = field(default_factory=list)
    is_dev: bool = False
    source: str = "pypi"
    extras: List[str] = field(default_factory=list)

    @property
    def pinned_spec(self) -> str:
        extras_str = f"[{','.join(self.extras)}]" if self.extras else ""
        return f"{self.name}{extras_str}=={self.version}"

    @property
    def requirement_line(self) -> str:
        line = self.pinned_spec
        if self.hashes:
            hash_lines = " \\\n    ".join(
                f"--hash={h}" for h in self.hashes
            )
            line += f" \\\n    {hash_lines}"
        return line


