def run_command(
    cmd: List[str],
    capture_output: bool = True,
    check: bool = True,
    cwd: Optional[Path] = None,
) -> subprocess.CompletedProcess:
    """Run a shell command with logging."""
    logger.debug(f"Running: {' '.join(cmd)}")
    try:
        result = subprocess.run(
            cmd,
            capture_output=capture_output,
            text=True,
            check=check,
            cwd=cwd or PROJECT_ROOT,
        )
        return result
    except subprocess.CalledProcessError as e:
        logger.error(f"Command failed: {' '.join(cmd)}")
        logger.error(f"STDOUT: {e.stdout}")
        logger.error(f"STDERR: {e.stderr}")
        raise


def detect_backend() -> Backend:
    """Auto-detect which dependency backend the project uses."""
    if (PROJECT_ROOT / POETRY_LOCK).exists() or _pyproject_uses_poetry():
        return Backend.POETRY
    if (PROJECT_ROOT / REQUIREMENTS_IN).exists():
        return Backend.PIP_TOOLS
    if (PROJECT_ROOT / REQUIREMENTS_TXT).exists():
        return Backend.PIP
    # Default to pip-tools as recommended
    return Backend.PIP_TOOLS


def _pyproject_uses_poetry() -> bool:
    """Check if pyproject.toml uses Poetry as the build backend."""
    pyproject = PROJECT_ROOT / PYPROJECT_TOML
    if not pyproject.exists():
        return False
    content = pyproject.read_text()
    return "tool.poetry" in content or "poetry-core" in content


def get_python_version() -> str:
    """Get the current Python version string."""
    return f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"


def get_platform_info() -> str:
    """Get platform information."""
    import platform
    return f"{platform.system()}-{platform.machine()}"


def compute_file_hash(filepath: Path, algorithm: str = "sha256") -> str:
    """Compute the hash of a file."""
    h = hashlib.new(algorithm)
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            h.update(chunk)
    return f"{algorithm}:{h.hexdigest()}"


def ensure_tool_installed(tool: str) -> bool:
    """Check if a CLI tool is available."""
    return shutil.which(tool) is not None


def install_tool(package: str) -> None:
    """Install a Python tool via pip."""
    logger.info(f"Installing {package}...")
    run_command([sys.executable, "-m", "pip", "install", package])


