class RequirementsParser:
    """Parse requirements.txt files (with or without hashes)."""

    @staticmethod
    def parse(filepath: Path) -> List[Dependency]:
        """Parse a requirements.txt file into Dependency objects."""
        if not filepath.exists():
            return []

        dependencies = []
        content = filepath.read_text()

        # Join continuation lines
        content = re.sub(r"\\\s*\n", " ", content)

        for line in content.splitlines():
            line = line.strip()
            if not line or line.startswith("#") or line.startswith("-"):
                continue

            dep = RequirementsParser._parse_line(line)
            if dep:
                dependencies.append(dep)

        return dependencies

    @staticmethod
    def _parse_line(line: str) -> Optional[Dependency]:
        """Parse a single requirement line."""
        # Extract hashes
        hashes = re.findall(r"--hash=(\S+)", line)
        line = re.sub(r"\s*--hash=\S+", "", line).strip()

        # Parse name, extras, and version
        match = re.match(
            r"^([A-Za-z0-9_.-]+)(?:\[([^\]]+)\])?(?:==([^\s;]+))?", line
        )
        if not match:
            return None

        name = match.group(1)
        extras = [e.strip() for e in match.group(2).split(",")] if match.group(2) else []
        version = match.group(3) or ""

        return Dependency(
            name=name,
            version=version,
            hashes=hashes,
            extras=extras,
        )

    @staticmethod
    def write(
        filepath: Path,
        dependencies: List[Dependency],
        header: Optional[str] = None,
    ) -> None:
        """Write dependencies to a requirements.txt file."""
        lines = []

        if header:
            for h_line in header.splitlines():
                lines.append(f"# {h_line}")
            lines.append("")

        lines.append(
            f"# Generated by dependency_manager.py on "
            f"{datetime.now().isoformat()}"
        )
        lines.append(
            f"# Python {get_python_version()} | {get_platform_info()}"
        )
        lines.append("")

        for dep in sorted(dependencies, key=lambda d: d.name.lower()):
            lines.append(dep.requirement_line)

        filepath.write_text("\n".join(lines) + "\n")
        logger.info(f"Wrote {len(dependencies)} dependencies to {filepath}")


